import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';
import toast from 'react-hot-toast';
import { QRCodeSVG } from 'react-qrcode';
import EvaluationCard from './EvaluationCard';

const StudentDashboard = () => {
  const { user } = useContext(AuthContext);
  const [dashboardData, setDashboardData] = useState({
    announcements: [],
    pendingEvaluations: [],
    certificates: []
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      const response = await api.get('/student/dashboard');
      setDashboardData(response.data);
    } catch (error) {
      toast.error('Failed to load dashboard');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-32 w-32 border-b-2 border-purple-600"></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto py-12 px-4 sm:px-6 lg:px-8">
      <div className="mb-8">
        <h1 className="text-4xl font-bold text-gray-900 mb-2">
          Welcome back, {user.fullName}!
        </h1>
        <p className="text-xl text-gray-600">
          Student ID: {user.studentId}
        </p>
      </div>

      {/* Announcements */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-12">
        <div className="bg-white rounded-2xl shadow-xl p-8">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Announcements</h2>
          <div className="space-y-4">
            {dashboardData.announcements.map((announcement, index) => (
              <div key={index} className="bg-blue-50 p-4 rounded-xl border-l-4 border-blue-500">
                <p className="text-gray-800">{announcement}</p>
              </div>
            ))}
          </div>
        </div>

        {/* Pending Evaluations */}
        <div className="bg-white rounded-2xl shadow-xl p-8">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">
            Pending Evaluations ({dashboardData.pendingEvaluations.length})
          </h2>
          {dashboardData.pendingEvaluations.length === 0 ? (
            <p className="text-gray-500 text-center py-8">No pending evaluations</p>
          ) : (
            <div className="space-y-4 max-h-96 overflow-y-auto">
              {dashboardData.pendingEvaluations.map((evaluation) => (
                <EvaluationCard key={evaluation._id} evaluation={evaluation} />
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Certificates */}
      <div className="bg-white rounded-2xl shadow-xl p-8">
        <h2 className="text-2xl font-bold text-gray-900 mb-6">Your Certificates</h2>
        {dashboardData.certificates.length === 0 ? (
          <p className="text-gray-500 text-center py-8">No certificates yet</p>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {dashboardData.certificates.map((cert) => (
              <div key={cert._id} className="border border-gray-200 rounded-xl p-6 hover:shadow-lg transition-shadow">
                <h3 className="font-semibold text-lg mb-2">{cert.eventName}</h3>
                <p className="text-sm text-gray-500 mb-4">
                  {new Date(cert.eventDate).toLocaleDateString()}
                </p>
                <div className="flex justify-center mb-4">
                  <QRCodeSVG value={cert.qrCode} size={120} />
                </div>
                <span className={`px-3 py-1 rounded-full text-xs font-medium ${
                  cert.status === 'verified' 
                    ? 'bg-green-100 text-green-800' 
                    : 'bg-yellow-100 text-yellow-800'
                }`}>
                  {cert.status}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default StudentDashboard;
